import numpy as np

def compute_modularity(A, labels):
    n = A.shape[0]
    m = A.sum() / 2.0
    if m == 0:
        return 0.0
    k = A.sum(axis=1)
    Q = 0.0
    for i in range(n):
        for j in range(n):
            if labels[i] == labels[j]:
                Q += A[i, j] - k[i] * k[j] / (2 * m)
    return Q / (2 * m)

def modularity_gain(A, node, target_community, labels, m):
    if m == 0:
        return 0.0
    k = A.sum(axis=1)
    # Nodes in target community
    in_community = np.where(labels == target_community)[0]
    # Sum of weights from node to target community
    k_i_in = A[node, in_community].sum()
    # Sum of degrees in target community
    sigma_tot = k[in_community].sum()
    k_i = k[node]
    gain = k_i_in - sigma_tot * k_i / (2 * m)
    return gain / m

def greedy_community_detection(A, max_iter=10):
    n = A.shape[0]
    labels = np.arange(n, dtype=int)
    m = A.sum() / 2.0
    if m == 0:
        return labels

    for _ in range(max_iter):
        improved = False
        for node in range(n):
            current_community = labels[node]
            neighbors = np.where(A[node] > 0)[0]
            neighbor_communities = set(labels[neighbors]) - {current_community}

            best_gain = 0.0
            best_community = current_community

            for community in neighbor_communities:
                # Temporarily remove node from current community
                labels[node] = -1
                gain = modularity_gain(A, node, community, labels, m)
                labels[node] = current_community
                if gain > best_gain:
                    best_gain = gain
                    best_community = community

            if best_community != current_community:
                labels[node] = best_community
                improved = True

        if not improved:
            break

    # Re-label communities as 0, 1, 2, ...
    unique_communities = np.unique(labels)
    remap = {old: new for new, old in enumerate(unique_communities)}
    labels = np.array([remap[l] for l in labels])
    return labels

